import{_ as n,o as t,c as i,a}from"./chunks/framework.8tiMeCK-.js";const s="/PenguinLab/assets/ch09_fig130.lLgZdASC.webp",g=JSON.parse('{"title":"9.3  Configuring the Kernel for ftrace Support","description":"","frontmatter":{},"headers":[],"relativePath":"en/notes/linux_kernel_debugging/ch09_3.md","filePath":"en/notes/linux_kernel_debugging/ch09_3.md","lastUpdated":null}'),o={name:"en/notes/linux_kernel_debugging/ch09_3.md"};function r(l,e,c,h,d,p){return t(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="_9-3-configuring-the-kernel-for-ftrace-support" tabindex="-1">9.3 Configuring the Kernel for ftrace Support <a class="header-anchor" href="#_9-3-configuring-the-kernel-for-ftrace-support" aria-label="Permalink to &quot;9.3  Configuring the Kernel for ftrace Support&quot;">​</a></h1><p>Most modern Linux distributions come with ftrace support enabled out of the box.</p><p>This makes perfect sense—when something goes wrong, you want a tool ready at hand rather than stumbling around blindly. In the kernel configuration, this master switch is called <code>CONFIG_FTRACE</code>, and it is typically already set to <code>y</code>. If you prefer the graphical <code>make menuconfig</code>, you can find the &quot;Tracers&quot; menu under &quot;Kernel hacking&quot;.</p><p>However, enabling this option has a prerequisite: <code>TRACING_SUPPORT</code>.</p><p>This is architecture-dependent (CPU type) and must be <code>y</code>. In practice, most common architectures (x86, ARM64, etc.) already satisfy this dependency. To give you a concrete idea, here is a screenshot of the configuration on a 5.10.60 kernel for x86_64:</p><p><img src="'+s+`" alt="figure"></p><p>*<em>Figure 9.3 – Screenshot of the Tracers submenu on x86_64 (5.10.60) with default options</em></p><p>Beyond the master switch, some specific tracers have their own dependencies. For example, to enable the &quot;Interrupts-off Latency Tracer&quot; (<code>CONFIG_IRQSOFF_TRACER</code>), you need <code>TRACE_IRQFLAGS_SUPPORT=y</code> (which is also typically enabled by default; we&#39;ll dive into these latency-specific tracers in the FAQ chapter later). Additionally, many options require the ability to display kernel stack traces (<code>CONFIG_STACKTRACE_SUPPORT=y</code>), but fortunately, these are standard in modern kernels.</p><p>If you want to dig into the details, all ftrace-related submenus and configuration options are defined in the <code>kernel/trace/Kconfig</code> file in the source tree. You can look up the descriptions of any options that interest you there.</p><h3 id="is-ftrace-actually-enabled-on-your-kernel" tabindex="-1">Is ftrace Actually Enabled on Your Kernel? <a class="header-anchor" href="#is-ftrace-actually-enabled-on-your-kernel" aria-label="Permalink to &quot;Is ftrace Actually Enabled on Your Kernel?&quot;">​</a></h3><p>Enough theory—let&#39;s tackle the practical question: is ftrace enabled on your system?</p><p>If you&#39;re running a general-purpose distribution like Ubuntu 20.04.3 LTS, the answer is almost certainly yes. We can verify this:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -w</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> CONFIG_FTRACE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /boot/config-5.11.0-46-generic</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> </span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">CONFIG_FTRACE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">y</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>There you go—it&#39;s <code>y</code>.</p><p>But what if you&#39;re working on an embedded project? That&#39;s harder to say. Go check your project&#39;s kernel configuration file, or simply <code>grep</code> it. On the custom 5.10.60 production kernel I work with, it is enabled.</p><p>On a related note, the technical reviewer for this book, Chi Thahn Hoang, has extensive experience in embedded Linux. He shared a crucial insight: <strong>in every project he has worked on, ftrace is always compiled into the kernel</strong>. Why? Because even though you don&#39;t use it day-to-day, it&#39;s an absolute lifesaver when the system goes wrong. Moreover, as long as you don&#39;t &quot;turn it on,&quot; its overhead is exactly zero.</p><p>This brings us to the next question: overhead.</p><h3 id="ftrace-and-system-overhead" tabindex="-1">Ftrace and System Overhead <a class="header-anchor" href="#ftrace-and-system-overhead" aria-label="Permalink to &quot;Ftrace and System Overhead&quot;">​</a></h3><p>You might be thinking: &quot;Even if I don&#39;t turn it on, as long as the feature is there, there must be <em>some</em> performance cost, right?&quot;</p><p>This intuition is both right and wrong. If ftrace were a simple &quot;on/off&quot; switch, the code would indeed need to litter every function entry and exit with conditional logic like this:</p><div class="language-c vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (tracing_enabled) {</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    // 做跟踪记录的事情</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>If that were the case, even when you aren&#39;t tracing, every function call would incur an extra <code>if</code> check. In a kernel where every nanosecond counts, this overhead would be unacceptable.</p><p>But the kernel developers came up with a brilliant (and slightly crazy) solution.</p><p>This configuration is called <strong><code>CONFIG_DYNAMIC_FTRACE</code></strong> (dynamic ftrace).</p><p>When enabled, the kernel does something astonishing at runtime—it directly modifies the machine code in memory. When tracing is off, it replaces the instruction at the function entry point with <code>NOP</code> (a no-op), which does absolutely nothing and incurs zero performance cost. When you need to trace a specific function, it dynamically replaces that instruction with a jump to the ftrace handling code (a mechanism commonly known as the <strong>Trampoline</strong>).</p><p>Therefore, by default, this option is enabled. This means:</p><ol><li>When not tracing, performance is native.</li><li>When tracing a small number of functions, performance is near-native.</li><li>Only when tracing all functions at full speed will there be a noticeable performance drop.</li></ol><hr><p>Now, let&#39;s get to the main event. Assuming your kernel is properly configured, we&#39;ll jump straight into the <code>/sys/kernel/tracing</code> directory and start flipping those control switches.</p><blockquote><p><strong>Note</strong>: The following operations require root privileges. If you are not the root user, many files will be read-only or completely inaccessible.</p></blockquote><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># cd /sys/kernel/tracing</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>(This is the first time we&#39;re explicitly spelling out this path. Note the <code>#</code> prompt, which indicates we are running as root; you&#39;ll need to <code>sudo -s</code> or prepend <code>sudo</code> to every command.)</p><p>The <code>tracefs</code> filesystem contains many control knobs (all pseudo-files, of course, just like <code>procfs</code> and <code>sysfs</code>). Among them is a file named <code>tracing_on</code>, which controls the actual on/off switch for the tracing functionality.</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ls -l tracing_on </span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">-rw-r--r--</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Jan</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 19</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 19:00</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tracing_on</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>What is its current value?</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># cat tracing_on </span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>It&#39;s <code>1</code>. This is intuitive—<code>0</code> means off, and <code>1</code> means on.</p><p><strong>Wait, ftrace is enabled by default? Won&#39;t that impact performance?</strong></p><p>Don&#39;t worry—there&#39;s a subtle detail here. Although <code>tracing_on</code> is <code>1</code>, ftrace is actually in a &quot;standby&quot; state.</p><p>You can think of <code>tracing_on</code> as the main breaker, but you also need to check what the current <code>current_tracer</code> (current tracer) is set to. If it&#39;s <code>nop</code> (i.e., No Operation), it means that even though the main breaker is on, no actual tracing probes have been installed, so the system is still running at native speed.</p><p>It&#39;s like turning on a light switch, but the bulb has no filament installed—no current flows, so no light is produced, and no electricity is consumed.</p><p>This is the benefit of <code>CONFIG_DYNAMIC_FTRACE</code>: only when you actually specify a tracer (like <code>function_graph</code>) does the kernel start modifying instructions and &quot;installing the filament.&quot; Until then, everything remains static and zero-overhead.</p>`,42)])])}const y=n(o,[["render",r]]);export{g as __pageData,y as default};
